import java.util.Scanner;

public class BufferOverflowExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String inputName = scanner.nextLine();

        // Vulnerability: Not checking the length of inputName before copying it to a fixed-size array
        char[] nameArray = new char[10];
        for (int i = 0; i < inputName.length(); i++) {
            nameArray[i] = inputName.charAt(i);
        }

        System.out.println("Your name is: " + String.valueOf(nameArray));
    }
}

